@endsection @push('scripts')<script>function syncMealOptions(form){const option=form.querySelector('.subscription-select')?.selectedOptions[0];if(!option)return;['breakfast','lunch','dinner'].forEach(meal=>{const input=form.querySelector('[name='+meal+'_required]');const subscribed=option.dataset[meal]==='1';input.disabled=!subscribed;if(!subscribed)input.checked=false})}document.querySelectorAll('.meal-hold-form').forEach(form=>{const select=form.querySelector('.subscription-select');select?.addEventListener('change',()=>syncMealOptions(form));syncMealOptions(form)});</script>@endpush
